function CustomListener.onConsumeDiamonds(rakssid, isSuccess, message, extra)
    local player = PlayerManager:getPlayerByRakssid(rakssid)
    if player == nil then
        return
    end
    local info = StringUtil.split(extra, "#")
    if #info == 2 then
        local extra1 = tostring(info[1])
        local extra2 = tonumber(info[2])
        if isSuccess == false then
            if extra1 == Define.BuySupplyBox then
                GameStore:onPlayerBuySupplyFailed(player, extra2)
            end
        else
            if extra1 == Define.BuyGoods then
                GameStore:onPlayerBuyGoodsSuccess(player, extra2)
            end
            if extra1 == Define.BuySupplyBox then
                GameStore:onPlayerBuySupplySuccess(player, extra2)
            end
        end
    end
end

return CustomListener